        var body = '<div class="wm-brand">' + escapeHTML(opts.logoText) + '</div><section class="line-hero"><div><div class="wm-kicker">Brand Line Manifesto</div><h1>Make the journey<br><span>visible.</span></h1><p>' + escapeHTML(opts.subtitle) + '</p></div></section><section class="line-section" id="lineSection"><div class="line-sticky"><svg class="line-svg" viewBox="0 0 420 760" preserveAspectRatio="none"><path class="line-path" id="manifestoPath" d="M210 20 C210 90 80 115 80 178 S340 250 340 315 S80 390 80 455 S340 530 340 594 S210 685 210 740"/></svg>' + nodes + '</div></section><section class="line-outro"><div class="wm-kicker">A line can hold a story</div><h2>' + escapeHTML(opts.headline) + '</h2><p>El trazo se revela con el recorrido y conecta hitos, producto y media. Es una estructura final para manifiestos de marca, roadmaps, casos de estudio y viajes de cliente.</p><a class="wm-cta" href="' + escapeAttr(safeUrl(opts.url)) + '">' + escapeHTML(opts.cta) + '</a></section><footer>' + escapeHTML(opts.logoText) + ' - Brand Line Manifesto final viewer</footer>';
        var scripts = gsapScripts() + '<script>(function(){var path=document.getElementById("manifestoPath"),steps=[].slice.call(document.querySelectorAll(".line-step"));if(!path)return;var len=path.getTotalLength();path.style.strokeDasharray=len;path.style.strokeDashoffset=len;function show(i){steps.forEach(function(step,n){step.classList.toggle("active",n<=i)})}if(window.gsap&&window.ScrollTrigger&&!matchMedia("(prefers-reduced-motion: reduce)").matches){gsap.registerPlugin(ScrollTrigger);gsap.to(path,{strokeDashoffset:0,ease:"none",scrollTrigger:{trigger:"#lineSection",start:"top top",end:"bottom bottom",scrub:' + (0.35 / opts.speed).toFixed(2) + '}});steps.forEach(function(step,i){ScrollTrigger.create({trigger:"#lineSection",start:(10+i*19)+"% top",end:(21+i*19)+"% top",onEnter:function(){show(i)},onEnterBack:function(){show(i)}})})}else{path.style.strokeDashoffset=0;show(steps.length-1)}})();<\\/script>';
