    // Independent adaptation of the RGB Dancer interaction: three user media
    // layers stay synchronised and separate spatially with pointer movement.
    // It does not depend on the original demo's remote dancer files.
    function buildRGBMotionTriptych(mediaList, rawOpts) {
        var opts = normalizeOptions(rawOpts);
        var media = [mediaAt(mediaList, 0), mediaAt(mediaList, 1), mediaAt(mediaList, 2)];
        var layers = media.map(function(item, index) {
            return '<div class="rgb-layer rgb-layer-' + index + '">' + mediaMarkup(item, 'rgb-media', 'Capa RGB ' + (index + 1)) + '</div>';
        }).join('');
        var css = baseCSS(opts) +
            'body{background:#020307}.rgb-hero{min-height:100dvh;position:relative;display:grid;place-items:center;overflow:hidden;padding:90px 24px}.rgb-hero:before{content:"";position:absolute;inset:0;background:radial-gradient(circle at 50% 45%,color-mix(in srgb,var(--accent),transparent 74%),transparent 35%),linear-gradient(180deg,#05060c 0%,#010104 100%)}.rgb-stage{position:absolute;inset:0;overflow:hidden;isolation:isolate}.rgb-layer{position:absolute;inset:-5%;opacity:.72;mix-blend-mode:screen;will-change:transform;transition:transform .12s linear,opacity .25s}.rgb-media{width:100%;height:100%;object-fit:cover;filter:grayscale(1) contrast(1.26) brightness(1.08)}.rgb-layer-0{filter:sepia(1) saturate(8) hue-rotate(295deg)}.rgb-layer-1{filter:sepia(1) saturate(8) hue-rotate(88deg)}.rgb-layer-2{filter:sepia(1) saturate(8) hue-rotate(178deg)}.rgb-vignette{position:absolute;inset:0;z-index:2;pointer-events:none;background:radial-gradient(circle at 50% 45%,transparent 15%,rgba(1,2,5,.2) 56%,rgba(0,0,0,.88) 100%)}.rgb-copy{position:relative;z-index:3;max-width:900px;text-align:center}.rgb-copy h1{margin:12px 0 18px;font-size:clamp(54px,10vw,150px);font-weight:900;letter-spacing:-.085em;line-height:.78;text-shadow:0 16px 80px rgba(0,0,0,.72)}.rgb-copy h1 span{color:var(--accent)}.rgb-copy p{max-width:630px;margin:0 auto 26px;color:rgba(255,255,255,.75);font-size:clamp(16px,2vw,20px);line-height:1.55}.rgb-instruction{display:inline-flex;align-items:center;gap:10px;margin-top:22px;color:rgba(255,255,255,.64);font-size:11px;font-weight:800;letter-spacing:.14em;text-transform:uppercase}.rgb-dot{width:8px;height:8px;border-radius:50%;background:var(--accent);box-shadow:0 0 20px var(--accent);animation:rgbPulse 1.4s ease-in-out infinite}@keyframes rgbPulse{50%{transform:scale(.45);opacity:.35}}.rgb-proof{position:absolute;z-index:3;bottom:22px;left:50%;transform:translateX(-50%);display:flex;gap:8px;flex-wrap:wrap;justify-content:center}.rgb-proof span{padding:8px 10px;border:1px solid rgba(255,255,255,.22);border-radius:999px;background:rgba(4,4,10,.36);backdrop-filter:blur(12px);font-size:10px;font-weight:800;letter-spacing:.1em;text-transform:uppercase}.rgb-section{display:grid;grid-template-columns:repeat(3,1fr);gap:1px;background:rgba(255,255,255,.13);padding:1px}.rgb-card{min-height:330px;padding:34px;background:#090a10}.rgb-card:nth-child(2){background:#0e0910}.rgb-card:nth-child(3){background:#091013}.rgb-card h2{font-size:clamp(26px,3vw,46px);letter-spacing:-.055em;line-height:.94;margin:12px 0}.rgb-card p{max-width:32ch;color:var(--muted);line-height:1.6}.rgb-card strong{color:var(--accent)}footer{border-top:1px solid var(--line);padding:28px;text-align:center;color:var(--muted);font-size:12px}@media(max-width:720px){.rgb-hero{padding:96px 20px 104px}.rgb-copy h1{font-size:clamp(56px,18vw,102px)}.rgb-layer{opacity:.6}.rgb-proof{width:calc(100% - 32px)}.rgb-section{grid-template-columns:1fr}.rgb-card{min-height:230px}.rgb-instruction{font-size:10px}}';
        var body = '<div class="wm-brand">' + escapeHTML(opts.logoText) + '</div><main><section class="rgb-hero"><div class="rgb-stage" id="rgbStage">' + layers + '<div class="rgb-vignette"></div></div><div class="rgb-copy"><div class="wm-kicker">RGB Motion Triptych PRO</div><h1>Move the <span>signal.</span></h1><p>' + escapeHTML(opts.subtitle) + '</p><a class="wm-cta" href="' + escapeAttr(safeUrl(opts.url)) + '">' + escapeHTML(opts.cta) + '</a><div class="rgb-instruction"><i class="rgb-dot"></i> Mueve o arrastra para separar las capas</div></div><div class="rgb-proof"><span>3 capas</span><span>vídeo o imagen</span><span>touch ready</span></div></section><section class="rgb-section"><article class="rgb-card"><div class="wm-kicker">Capa R</div><h2>Impacto inmediato.</h2><p>Un gesto convierte una pieza visual en una escena de campaña reactiva.</p></article><article class="rgb-card"><div class="wm-kicker">Capa G</div><h2>Señal con ritmo.</h2><p>Las capas se mantienen sincronizadas incluso cuando se usan tres vídeos propios.</p></article><article class="rgb-card"><div class="wm-kicker">Capa B</div><h2>Hecho para compartir.</h2><p><strong>Eventos, música, moda y lanzamientos</strong> ganan una interacción memorable sin exponer el editor.</p></article></section></main><footer>' + escapeHTML(opts.logoText) + ' - RGB Motion Triptych final viewer</footer>';
        var scripts = '<script>(function(){var stage=document.getElementById("rgbStage"),layers=[].slice.call(document.querySelectorAll(".rgb-layer")),videos=[].slice.call(document.querySelectorAll(".rgb-media")).filter(function(el){return el.tagName==="VIDEO"}),reduced=matchMedia("(prefers-reduced-motion: reduce)").matches,amount=' + (opts.intensity * 34).toFixed(1) + ',speed=' + opts.speed.toFixed(1) + ';function move(x,y){if(reduced)return;var dx=(x/innerWidth-.5)*amount,dy=(y/innerHeight-.5)*amount;layers.forEach(function(layer,i){var sign=i===0?-1:i===2?1:0;layer.style.transform="translate("+(sign*dx+(i===1?Math.sin(Date.now()*.001*speed)*3:0))+"px,"+(sign*dy)+"px) scale("+(1.02+Math.abs(sign)*.025)+")"})}function sync(source){videos.forEach(function(video){if(video!==source&&Math.abs(video.currentTime-source.currentTime)>.18){try{video.currentTime=source.currentTime}catch(e){}}})}stage.addEventListener("pointermove",function(e){move(e.clientX,e.clientY)});stage.addEventListener("pointerleave",function(){layers.forEach(function(layer){layer.style.transform="translate(0,0) scale(1.02)"})});videos.forEach(function(video){video.addEventListener("play",function(){sync(video)});video.addEventListener("timeupdate",function(){if(video===videos[0])sync(video)})});})();<\\/script>';
        return baseHead('RGB Motion Triptych PRO', opts) + css + closeDoc(body, scripts, 'Interaction architecture independently adapted for Escaparates Pro from the RGB Dancer reference. Client media is injected locally; no original demo media is exported.');
    }

